{| class="{{#ifeq:{{NAMESPACE}}|{{TALKSPACE}}|{{#ifeq:{{{small|}}}|yes|small|standard}}-talk}} messagebox"
| {{#if:{{{header|}}}|rowspan="2"}} align="center" style="width:35px;"|[[Image:{{{image|Info {{#ifeq:{{NAMESPACE}}|{{TALKSPACE}}||non-}}talk.png}}}|{{#ifeq:{{{small|}}}|yes|25px|35px}}|Notice]]
