{{pp-template}}

{{Documentation}}
<!-- PLEASE ADD CATEGORIES AND INTERWIKIS TO THE /doc SUBPAGE, THANKS -->
</noinclude>

{{main talk other
| demospace = {{{demospace|}}}
| 1 =   <!--Articles (main space)-->
  {{ambox | type=notice
  | image = [[Image:{{{image|Info non-talk.png}}}|40px|Notice]]
  | text = {{#if:{{{header|}}}| 
      <div style="text-align:center;">'''Notice: {{{header}}}'''</div>
    }}{{{1}}}
  }}
| 2 =   <!--Talk pages-->
  <table class="messagebox 
    {{#ifeq:{{{small|}}}|yes|small-talk|standard-talk}}">
  <tr><td>[[Image:{{{image|Info talk.png}}}| 
    {{#ifeq:{{{small|}}}|yes|30px|40px}}|Notice]]
  <td align="left" width="100%">{{#if:{{{header|}}}| 
      <div style="text-align:center;">'''Notice: {{{header}}}'''</div>
    }}{{{1}}}
  </table>
| 3 =   <!--Other pages-->
  <table class="messagebox">
  <tr><td align="center">[[Image:{{{image|Info non-talk.png}}}| 
    40px|Notice]]
  <td align="left" width="100%">{{#if:{{{header|}}}|
      <div style="text-align:center;">'''Notice: {{{header}}}'''</div>
    }}{{{1}}}
  </table>
}}<noinclude>

{{pp-template|small=yes}}
{{documentation}}
<!-- Add categories and interwikis to the /doc subpage, not here! -->
</noinclude>

{{talk other
| demospace = {{{demospace|}}}
| 1 =   <!--Talk pages-->
  <table class="messagebox
    {{#ifeq:{{{small|}}}|yes|small|standard}}-talk">
  <tr><td>[[Image:{{{image|Info talk.png}}}|{{#ifeq:{{{small|}}}|yes|3|4}}0px|Notice]]
  <td align="left" width="100%">{{#if:{{{header|}}}|
      <div style="text-align:center;">'''Notice: {{{header}}}'''</div>
    }}{{{1}}}
  </table>
| 2 =   <!--Other pages-->
  {{mbox
  | type = notice
